int main() {
  int T, N, S, P, V, maxProfit = 0;
  scanf("%d", &T);
  while (T--) {
    scanf("%d", &N);
    while (N--) {
      scanf("%d %d %d", &S, &P, &V);
      maxProfit = max(maxProfit, (P + S - 1) / S * V);
    }
    printf("%d\n", maxProfit);
  }
  return 0;
}

