code.Java:
public class Main {
  public static void main(String[] args) {
    java.util.Scanner sc = new java.util.Scanner(System.in);
    int T = sc.nextInt();
    while (T-- > 0) {
      int N = sc.nextInt();
      int maxProfit = 0;
      while (N-- > 0) {
        int S = sc.nextInt();
        int P = sc.nextInt();
        int V = sc.nextInt();
        maxProfit = Math.max(maxProfit, (P + S - 1) / S * V);
      }
      System.out.println(maxProfit);
    }
  }
}

