const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/
/);
let T = parseInt(input.shift());
while (T--) {
  let N = parseInt(input.shift());
  let maxProfit = 0;
  while (N--) {
    let [S, P, V] = input.shift().split(' ').map(Number);
    maxProfit = Math.max(maxProfit, Math.floor((P + S - 1) / S) * V);
  }
  console.log(maxProfit);
}
